import React, { useState, useCallback } from 'react';
import { Button, Select, MoneyInput, NumberInput, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { OpeningInventoryDto } from '../../../services/kt/models';
import { yearOptions } from '../../../constants/voucher';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-so-du-vat-tu';

const SoDuVatTuPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [year, setYear] = useState(String(new Date().getFullYear()));
  const [items, setItems] = useState<OpeningInventoryDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  const load = useCallback(() => {
    setLoading(true);
    ktService.getOpeningInventory(Number(year))
      .then(setItems)
      .catch(err => dispatch(addToast({ message: getApiErrorMessage(err, 'Lỗi tải số dư VT'), type: 'error' })))
      .finally(() => setLoading(false));
  }, [year, dispatch]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  const updateItem = (
    idx: number,
    field: 'quantity' | 'unitPrice',
    val: number,
  ) => {
    setItems(prev => prev.map((it, i) => {
      if (i !== idx) return it;
      const quantity = field === 'quantity' ? val : it.quantity;
      const unitPrice = field === 'unitPrice' ? val : it.unitPrice;
      return { ...it, quantity, unitPrice, amount: quantity * unitPrice };
    }));
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      await ktService.saveOpeningInventory({ year: Number(year), items });
      dispatch(addToast({ message: 'Lưu số dư vật tư thành công', type: 'success' }));
      load();
    } catch (e: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(e, 'Lỗi lưu'), type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className={erp.page} data-testid={TEST_ID}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}>
          <h1 className={erp.title}><i className="fas fa-boxes" /> Số dư vật tư đầu kỳ</h1>
        </div>
      </div>
      <div className={erp.filtersBar} data-testid={`${TEST_ID}-filters`}>
        <Select
          value={year}
          onChange={e => setYear(e.target.value)}
          options={yearOptions()}
          data-testid={`${TEST_ID}-year`}
        />
        <Button variant="primary" onClick={handleSave} loading={saving} data-testid={`${TEST_ID}-save`}>Lưu</Button>
        <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={load} onRefresh={load} showSearch={false} />
      </div>
      <div className={erp.tableCard} data-testid={`${TEST_ID}-table`}>
        {loading ? <div className={erp.loading}>Đang tải...</div> : items.length === 0 ? (
          <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>Chưa có số dư vật tư năm {year}</div>
        ) : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead>
                <tr>
                  <th>Mã VT</th>
                  <th>Tên vật tư</th>
                  <th>Kho</th>
                  <th className={erp.colRight}>SL</th>
                  <th className={erp.colRight}>Đơn giá</th>
                  <th className={erp.colRight}>Giá trị</th>
                </tr>
              </thead>
              <tbody>{items.map((it, idx) => (
                <tr key={`${it.materialCode}-${it.warehouseId}`} data-testid={`${TEST_ID}-row-${idx + 1}`}>
                  <td><code>{it.materialCode}</code></td>
                  <td>{it.materialName ?? '—'}</td>
                  <td>{it.warehouseName ?? '—'}</td>
                  <td>
                    <NumberInput
                      value={it.quantity}
                      onChange={val => updateItem(idx, 'quantity', val)}
                      data-testid={`${TEST_ID}-row-${idx + 1}-qty`}
                    />
                  </td>
                  <td>
                    <MoneyInput
                      value={it.unitPrice}
                      onChange={val => updateItem(idx, 'unitPrice', val)}
                      data-testid={`${TEST_ID}-row-${idx + 1}-price`}
                    />
                  </td>
                  <td className={erp.colRight}>{formatVnd(it.amount)}</td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default SoDuVatTuPage;
